-- gen_chdl_access_v2.lua
-- Plain Lua code generator for ChdlAccess{Single,Double,Multi}.lua
-- Replaces the LuaJIT-Pro based gen_chdl_access.lua
-- Key optimization: functions are created once at module load time (singleton pattern)
-- All instances of the same beat_num variant share the same function objects → monomorphic call sites

local out_dir = "./out"

local header_base = [[---@diagnostic disable: redundant-parameter
----------------------------------------------------
-- Auto generated by gen_chdl_access.lua
-- DO NOT edit this file!
----------------------------------------------------

local vpiml = require "verilua.vpiml.vpiml"
local BitVec = require "verilua.utils.BitVec"
local table_new = require "table.new"

local assert = assert
local f = string.format
]]

-- Extra imports needed by Double/Multi for type-based auto-dispatch
local header_type_dispatch = [[local ffi = require "ffi"
local type = type
local ffi_istype = ffi.istype
]]

-- Helper: generate the stub error table for uninitialized APIs
local function gen_stubs(chdl_apis, chdl_array_apis)
    local lines = {}
    lines[#lines + 1] = "local chdl = {"
    for _, api in ipairs(chdl_apis) do
        lines[#lines + 1] = string.format(
            '    %s = function(this) assert(false, f("<chdl>:%s() is not implemented! fullpath => %%s bitwidth => %%d", this.fullpath, this.width)) end,',
            api, api)
    end
    lines[#lines + 1] = "}"
    lines[#lines + 1] = ""
    lines[#lines + 1] = "local chdl_array = {"
    for _, api in ipairs(chdl_array_apis) do
        lines[#lines + 1] = string.format(
            '    %s = function(this) assert(false, f("Normal handle does not support <chdl>:at(), fullpath => %%s bitwidth => %%d is_array => %%s", this.fullpath, this.width, tostring(this.is_array))) end,',
            api, api)
    end
    lines[#lines + 1] = "}"
    lines[#lines + 1] = ""
    return table.concat(lines, "\n")
end

local chdl_apis = {
    "get", "get64", "set", "set_imm", "set_unsafe", "set_imm_unsafe",
    "set_cached", "set_imm_cached", "set_bitfield", "set_imm_bitfield",
    "set_bitfield_hex_str", "set_imm_bitfield_hex_str",
    "set_force", "set_release",
}

local chdl_array_apis = {
    "at", "get_index", "set_index", "set_imm_index",
    "set_index_unsafe", "set_imm_index_unsafe",
    "get_index_all", "get_index_bitvec",
    "set_index_bitfield", "set_imm_index_bitfield",
    "set_index_bitfield_hex_str", "set_imm_index_bitfield_hex_str",
    "set_index_all", "set_imm_index_all",
    "set_index_unsafe_all", "set_imm_index_unsafe_all",
}

-- Load variant-specific body generators
local gen_single = require "gen_chdl_single"
local gen_double = require "gen_chdl_double"
local gen_multi = require "gen_chdl_multi"

local stubs = gen_stubs(chdl_apis, chdl_array_apis)

local footer = [[

-- Pre-built combined table (methods + array_methods merged at load time)
local M_combined = {}
for k, v in pairs(chdl) do M_combined[k] = v end
for k, v in pairs(chdl_array) do M_combined[k] = v end

return function(is_array)
    return is_array and M_combined or chdl
end
]]

local function write_file(filename, body, needs_type_dispatch)
    local path = out_dir .. "/" .. filename
    local fh = assert(io.open(path, "w"))
    fh:write(header_base)
    if needs_type_dispatch then
        fh:write(header_type_dispatch)
    end
    fh:write(stubs)
    fh:write(body)
    fh:write(footer)
    fh:close()
    print("Generated: " .. path)
end

os.execute("mkdir -p " .. out_dir)
write_file("ChdlAccessSingle.lua", gen_single(), false)
write_file("ChdlAccessDouble.lua", gen_double(), true)
write_file("ChdlAccessMulti.lua", gen_multi(), true)
print("Done.")
